INSERT INTO `v1_0dbe677e52275915f48037fd5c46e950fdfcbe1920d5b2deca0d512dda0d422b` VALUES ("【魔法】深域の力を我が物に画策する小鬼学者。\n禁忌の劇毒を創出し、全ての自由を強奪する。\n\n【特殊効果】\n・飛行効果無視\n・全スキルダメージＴＰ回復不可\n【ユニオンバースト】\n・敵全体にバリア解除\n・敵全体に魔法割合ダメージ\n・敵の数が少ないほど：ダメージアップ\n【スキル１】\n・敵全体に魔法ダメージ\n・物理攻撃をする敵全体に物理攻撃力ダウン\n　（必中）\n・敵の数が少ないほど：ダウン量アップ\n・魔法攻撃をする敵全体に魔法攻撃力ダウン\n　（必中）\n・敵の数が少ないほど：ダウン量アップ\n【スキル２】\n・前から敵２体に魔法ダメージ\n・前から敵２体に麻痺／猛毒（必中）", 924273101);
